use actix_web::{web, HttpResponse, Responder};
use sqlx::PgPool;
use uuid::Uuid;
use crate::models::post::{Post, CreatePost, UpdatePost};

pub fn config(cfg: &mut web::ServiceConfig) {
    cfg.service(
        web::scope("/posts")
            .route("", web::get().to(list))
            .route("", web::post().to(create))
            .route("/{id}", web::get().to(get_by_id))
            .route("/{id}", web::put().to(update))
            .route("/{id}", web::delete().to(delete)),
    );
}

async fn list(pool: web::Data<PgPool>) -> impl Responder {
    match sqlx::query_as::<_, Post>("SELECT * FROM posts ORDER BY id")
        .fetch_all(pool.get_ref())
        .await
    {
        Ok(rows) => HttpResponse::Ok().json(rows),
        Err(_) => HttpResponse::InternalServerError().finish(),
    }
}

async fn get_by_id(
    pool: web::Data<PgPool>,
    path: web::Path<uuid::Uuid>,
) -> impl Responder {
    let id = path.into_inner();
    match sqlx::query_as::<_, Post>("SELECT * FROM posts WHERE id = $1")
        .bind(id)
        .fetch_optional(pool.get_ref())
        .await
    {
        Ok(Some(row)) => HttpResponse::Ok().json(row),
        Ok(None) => HttpResponse::NotFound().finish(),
        Err(_) => HttpResponse::InternalServerError().finish(),
    }
}

async fn create(
    pool: web::Data<PgPool>,
    body: web::Json<CreatePost>,
) -> impl Responder {
    match sqlx::query_as::<_, Post>(
        "INSERT INTO posts (id, title, body, published) VALUES ($1, $2, $3, $4) RETURNING *",
    )
        .bind(Uuid::new_v4())
        .bind(body.title.clone())
        .bind(body.body.clone())
        .bind(body.published.clone())
        .fetch_one(pool.get_ref())
        .await
    {
        Ok(row) => HttpResponse::Created().json(row),
        Err(_) => HttpResponse::InternalServerError().finish(),
    }
}

async fn update(
    pool: web::Data<PgPool>,
    path: web::Path<uuid::Uuid>,
    body: web::Json<UpdatePost>,
) -> impl Responder {
    let id = path.into_inner();
    match sqlx::query_as::<_, Post>(
        "UPDATE posts SET title = COALESCE($2, title), body = COALESCE($3, body), published = COALESCE($4, published) WHERE id = $1 RETURNING *",
    )
        .bind(id)
        .bind(body.title.clone())
        .bind(body.body.clone())
        .bind(body.published.clone())
        .fetch_optional(pool.get_ref())
        .await
    {
        Ok(Some(row)) => HttpResponse::Ok().json(row),
        Ok(None) => HttpResponse::NotFound().finish(),
        Err(_) => HttpResponse::InternalServerError().finish(),
    }
}

async fn delete(
    pool: web::Data<PgPool>,
    path: web::Path<uuid::Uuid>,
) -> impl Responder {
    let id = path.into_inner();
    match sqlx::query("DELETE FROM posts WHERE id = $1")
        .bind(id)
        .execute(pool.get_ref())
        .await
    {
        Ok(r) if r.rows_affected() > 0 => HttpResponse::NoContent().finish(),
        Ok(_) => HttpResponse::NotFound().finish(),
        Err(_) => HttpResponse::InternalServerError().finish(),
    }
}

