mod config;
mod db;
mod handlers;
mod models;

use actix_web::{web, App, HttpServer};

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    // JSON-formatted tracing output — parseable by Loki / Datadog / CloudWatch.
    tracing_subscriber::fmt()
        .json()
        .with_env_filter(tracing_subscriber::EnvFilter::from_default_env())
        .init();
    dotenvy::dotenv().ok();
    let cfg = config::Config::from_env();
    let pool = db::connect(&cfg.database_url).await;
    let pool_data = actix_web::web::Data::new(pool);

    let addr = format!("0.0.0.0:{}", cfg.port);
    tracing::info!("listening on {}", addr);

    HttpServer::new(move || {
        App::new()
            .app_data(pool_data.clone())
            .route("/health", web::get().to(|| async { actix_web::HttpResponse::Ok().body("ok") }))
            .route("/health", web::get().to(|| async { actix_web::HttpResponse::Ok().json(serde_json::json!({"ok": true, "op": "GET /health"})) }))
            .route("/users", web::get().to(|| async { actix_web::HttpResponse::Ok().json(serde_json::json!({"ok": true, "op": "GET /users"})) }))
            .route("/users", web::post().to(|| async { actix_web::HttpResponse::Ok().json(serde_json::json!({"ok": true, "op": "POST /users"})) }))
            .route("/users/{id}", web::get().to(|| async { actix_web::HttpResponse::Ok().json(serde_json::json!({"ok": true, "op": "GET /users/:id"})) }))
            .route("/users/{id}", web::delete().to(|| async { actix_web::HttpResponse::Ok().json(serde_json::json!({"ok": true, "op": "DELETE /users/:id"})) }))
            .configure(handlers::user::config)
            .configure(handlers::post::config)
    })
    .bind(&addr)?
    // Actix's HttpServer::run already installs SIGTERM/SIGINT handlers and
    // drains in-flight requests with a 30 s timeout — which matches the K8s
    // default terminationGracePeriodSeconds. Tune via `.shutdown_timeout(...)`
    // if your pod spec overrides the grace period.
    .run()
    .await
}

